body.raw:
{
    "query": "query { patients(limit: 10) { items { id name { family given } gender birthDate } total page count } }"
}

{
    "query": "query($id: String!) { patient(id: $id) { id name { family given } gender birthDate telecom { system value } address { line city state postalCode country } } }",
    "variables": {
        "id": "{{patient_id}}"
    }
}

{
    "query": "query($practitioner: String!) { patients(generalPractitioner: $practitioner) { items { id name { family given } gender birthDate } total } }",
    "variables": {
        "practitioner": "Practitioner/{{practitioner_id}}"
    }
}

{
    "query": "mutation($input: CreatePatientInput!) { createPatient(input: $input) { patient { id name { family given } gender birthDate } } }",
    "variables": {
        "input": {
            "name": [{
                "family": "Smith",
                "given": ["John", "Adam"]
            }],
            "gender": "male",
            "birthDate": "1980-01-01",
            "telecom": [{
                "system": "phone",
                "value": "555-123-4567",
                "use": "home"
            }, {
                "system": "email",
                "value": "john.smith@example.com"
            }],
            "address": [{
                "use": "home",
                "line": ["123 Main St"],
                "city": "Anytown",
                "state": "CA",
                "postalCode": "12345",
                "country": "USA"
            }],
            "active": true,
            "generalPractitioner": [{
                "reference": "Practitioner/{{practitioner_id}}",
                "display": "Dr. Jane Doe"
            }]
        }
    }
}

{
    "query": "mutation($id: String!, $input: UpdatePatientInput!) { updatePatient(id: $id, input: $input) { patient { id name { family given } gender birthDate telecom { system value } } } }",
    "variables": {
        "id": "{{patient_id}}",
        "input": {
            "name": [{
                "family": "Smith",
                "given": ["John", "Updated"]
            }],
            "telecom": [{
                "system": "phone",
                "value": "555-987-6543",
                "use": "home"
            }, {
                "system": "email",
                "value": "john.updated@example.com"
            }]
        }
    }
}

{
    "query": "query { _entities(representations: [{__typename: \"Patient\", id: \"{{patient_id}}\"}]) { ... on Patient { id name { family given } gender birthDate } } }"
}
